export default function BarcodePage() {
  const [barcodes, setBarcodes] = React.useState<BarcodeItem[]>(initialBarcodes)
  const [selectedIds, setSelectedIds] = React.useState<Set<string>>(new Set())
  const [isUploadDialogOpen, setIsUploadDialogOpen] = React.useState(false)
  const [uploadPreview, setUploadPreview] = React.useState<BarcodeItem[]>([])
  const fileInputRef = React.useRef<HTMLInputElement>(null)

  const parseCSV = (csvText: string): BarcodeItem[] => {
    const lines = csvText.trim().split("\n")
    if (lines.length < 2) return []

    // Parse header to find column indices
    const header = lines[0].split(",").map((h) => h.trim().toLowerCase().replace(/"/g, ""))
    const barcodeIndex = header.findIndex((h) => h.includes("barcode") || h.includes("code"))
    const lenderIndex = header.findIndex((h) => h.includes("lender") || h.includes("bank"))
    const dateIndex = header.findIndex((h) => h.includes("date") || h.includes("created"))

    if (barcodeIndex === -1) return []

    const newBarcodes: BarcodeItem[] = []
    const existingCodes = new Set(barcodes.map((b) => b.code))
    let nextId = barcodes.length + 1

    for (let i = 1; i < lines.length; i++) {
      const values = lines[i].split(",").map((v) => v.trim().replace(/"/g, ""))
      const code = values[barcodeIndex] || ""
      
      if (!code || existingCodes.has(code)) continue

      const lenderName = lenderIndex !== -1 ? values[lenderIndex] || "" : ""
      const createdAt = dateIndex !== -1 ? values[dateIndex] || new Date().toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" }) : new Date().toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })

      newBarcodes.push({
        id: String(nextId++),
        code,
        lenderName,
        createdAt,
        isUsed: lenderName.trim() !== "",
      })
      existingCodes.add(code)
    }

    return newBarcodes
  }

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    const reader = new FileReader()
    reader.onload = (event) => {
      const csvText = event.target?.result as string
      const parsedBarcodes = parseCSV(csvText)
      setUploadPreview(parsedBarcodes)
      setIsUploadDialogOpen(true)
    }
    reader.readAsText(file)

    // Reset file input
    if (fileInputRef.current) {
      fileInputRef.current.value = ""
    }
  }

  const handleConfirmUpload = () => {
    if (uploadPreview.length > 0) {
      setBarcodes((prev) => [...prev, ...uploadPreview])
      setUploadPreview([])
      setIsUploadDialogOpen(false)
    }
  }

  const stats = React.useMemo(() => {
    const total = barcodes.length
    const used = barcodes.filter((b) => b.isUsed).length
    const available = total - used
    return { total, used, available }
  }, [barcodes])

  const handleMarkAsUsed = (count: number, lenderName: string) => {
    // Get all available (unused) barcodes
    const availableBarcodes = barcodes.filter((b) => !b.isUsed)
    // Select the first 'count' available barcodes to mark as used
    const barcodesToMark = availableBarcodes.slice(0, count)
    const idsToMark = new Set(barcodesToMark.map((b) => b.id))

    setBarcodes((prev) =>
      prev.map((b) =>
        idsToMark.has(b.id) ? { ...b, isUsed: true, lenderName } : b
      )
    )
    setSelectedIds(new Set())
  }

  const handleMarkSingleAsUsed = (id: string, lenderName: string) => {
    setBarcodes((prev) =>
      prev.map((b) => (b.id === id ? { ...b, isUsed: true, lenderName } : b))
    )
    setSelectedIds((prev) => {
      const newSet = new Set(prev)
      newSet.delete(id)
      return newSet
    })
  }

  const handleResetBarcode = (id: string) => {
    setBarcodes((prev) =>
      prev.map((b) =>
        b.id === id ? { ...b, isUsed: false, lenderName: "", resetAt: Date.now() } : b
      )
    )
  }

  const handleResetComplete = (id: string) => {
    setBarcodes((prev) =>
      prev.map((b) => (b.id === id ? { ...b, resetAt: undefined } : b))
    )
  }

  return (
    <div className="min-h-screen bg-background">
      <header className="border-b border-border bg-card">
        <div className="mx-auto max-w-7xl px-4 py-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="flex h-9 w-9 items-center justify-center rounded-lg bg-primary">
                <Barcode className="h-5 w-5 text-primary-foreground" />
              </div>
              <div>
                <h1 className="text-xl font-semibold text-foreground">
                  Barcode Portal
                </h1>
                <p className="text-sm text-muted-foreground">
                  Manage and track your product barcodes
                </p>
              </div>
            </div>
            <div>
              <input
                type="file"
                accept=".csv"
                onChange={handleFileChange}
                ref={fileInputRef}
                className="hidden"
                id="csv-upload"
              />
              <Button
                onClick={() => fileInputRef.current?.click()}
                variant="outline"
                className="gap-2"
              >
                <Upload className="h-4 w-4" />
                Upload CSV
              </Button>
            </div>
          </div>
        </div>
      </header>

      <main className="mx-auto max-w-7xl px-4 py-6 sm:px-6 lg:px-8">
        <div className="flex flex-col gap-6">
          <BarcodeStats
            total={stats.total}
            used={stats.used}
            available={stats.available}
          />

          <div className="flex flex-col gap-2">
            <h2 className="text-lg font-medium text-foreground">
              Barcode Inventory
            </h2>
            <p className="text-sm text-muted-foreground">
              Select unused barcodes to mark them as used. Used barcodes cannot
              be selected.
            </p>
          </div>

          <BarcodeTable
            barcodes={barcodes}
            selectedIds={selectedIds}
            onSelectionChange={setSelectedIds}
            onMarkAsUsed={handleMarkAsUsed}
            onMarkSingleAsUsed={handleMarkSingleAsUsed}
            onResetBarcode={handleResetBarcode}
            onResetComplete={handleResetComplete}
          />
        </div>
      </main>

      <Dialog open={isUploadDialogOpen} onOpenChange={setIsUploadDialogOpen}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Upload Barcodes</DialogTitle>
            <DialogDescription>
              Preview the barcodes to be imported from your CSV file.
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-4 py-4">
            {uploadPreview.length === 0 ? (
              <p className="text-sm text-muted-foreground text-center py-4">
                No valid barcodes found in the CSV file. Make sure it has a column named &quot;Barcode&quot; or &quot;Code&quot;.
              </p>
            ) : (
              <>
                <div className="text-sm text-muted-foreground">
                  Found {uploadPreview.length} new barcode(s):
                  <ul className="mt-2 list-disc list-inside">
                    <li>{uploadPreview.filter((b) => b.isUsed).length} with lender name (will be marked as Used)</li>
                    <li>{uploadPreview.filter((b) => !b.isUsed).length} without lender name (will be marked as Available)</li>
                  </ul>
                </div>
                <div className="max-h-48 overflow-y-auto rounded-lg border border-border">
                  <table className="w-full text-sm">
                    <thead className="bg-muted/50 sticky top-0">
                      <tr>
                        <th className="text-left px-3 py-2 font-medium">Barcode</th>
                        <th className="text-left px-3 py-2 font-medium">Lender</th>
                        <th className="text-left px-3 py-2 font-medium">Status</th>
                      </tr>
                    </thead>
                    <tbody>
                      {uploadPreview.map((b) => (
                        <tr key={b.id} className="border-t border-border">
                          <td className="px-3 py-2 font-mono">{b.code}</td>
                          <td className="px-3 py-2 text-muted-foreground">{b.lenderName || "-"}</td>
                          <td className="px-3 py-2">
                            <span className={`text-xs px-2 py-0.5 rounded-full ${b.isUsed ? "bg-muted text-muted-foreground" : "bg-success/20 text-success"}`}>
                              {b.isUsed ? "Used" : "Available"}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </>
            )}
          </div>
          <DialogFooter className="gap-2 sm:gap-0">
            <Button
              variant="outline"
              onClick={() => {
                setIsUploadDialogOpen(false)
                setUploadPreview([])
              }}
            >
              Cancel
            </Button>
            <Button
              onClick={handleConfirmUpload}
              disabled={uploadPreview.length === 0}
            >
              Import {uploadPreview.length} Barcode(s)
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}
